def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    epsilon = 1e-12
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 3:
            score -= 150 * (ratio - 3)**3
            for j in range(1, 5):
                score += ((-1)**j) * (ratio**(j+1)) / (j**1.5 + epsilon)
        elif ratio > 1.5:
            score -= 50 * (ratio - 1.5)**2
            if ratio < 2:
                score -= 10 / (2 - ratio + epsilon)
            else:
                score += 25 * np.sin(ratio * np.pi / 2)
        elif ratio > 1:
            score -= 10 * (ratio - 1)
            for k in range(2, 7):
                if abs(ratio - k*0.15) < 0.05:
                    score += 30 / (abs(ratio - k*0.15) + epsilon)
                    break
        else:
            for p in range(1, 8):
                boundary = p * 0.125
                if ratio < boundary:
                    score += (p ** 3) / (boundary - ratio + epsilon)
                    if p % 2 == 0:
                        score += 3 * np.log(boundary / (ratio + epsilon) + epsilon)
                    break
            else:
                score += 7 * (1 - ratio)**2
        penalty = 0.0
        for x in range(1, 6):
            term = ((-1)**x) * (ratio ** (x*3)) / (x + epsilon)
            penalty += term
        score += penalty
        if item > capacity:
            score -= 100
            mod = 0
            for m in range(1, 5):
                if capacity == 0:
                    break
                mod += ((item % (capacity + m)) / (m * 2 + epsilon))
            score += mod
        elif (capacity - item) < 0.15 * capacity:
            score += 20 * np.tanh((capacity - item) / (capacity + epsilon) * 10)
        else:
            if ratio < 0.25:
                score -= 8 * np.exp(-ratio * 15)
                for z in range(1, 4):
                    score += np.cos(ratio * np.pi * z)
        if score > 0 and ratio < 0.5:
            score += 5 * (0.5 - ratio) ** 1.5
        elif score < -50:
            score -= 10 * np.log(abs(score) + 1)
        priorities[i] = score
    finite_scores = priorities[np.isfinite(priorities)]
    if finite_scores.size > 0:
        max_p = np.max(finite_scores)
        min_p = np.min(finite_scores)
        if max_p > 0 and min_p < 0:
            norm = max_p - min_p + epsilon
            priorities = np.where(np.isfinite(priorities), (priorities - min_p) / norm, -np.inf)
        elif max_p > 0:
            priorities = np.where(np.isfinite(priorities), priorities / max_p, -np.inf)
    return priorities
